sys_script_include.script:
var TRACENowConfig = Class.create();

TRACENowConfig.prototype = {

    initialize: function() {},

    // Fields always exported regardless of table schema
    MANDATORY_FIELDS: [
        'number',
        'sys_id',
        'sys_created_on',
        'sys_updated_on',
        'sys_created_by',
        'sys_updated_by'
    ],

    // Fields to always skip during import (platform manages these)
    SKIP_ON_IMPORT: [
        'sys_class_name',
        'sys_mod_count',
        'sys_tags'
    ],

    // TRACENow metadata column prefix in Excel
    META_PREFIX: 'TRN_',

    // Column names in Excel for mandatory fields
    COL_NUMBER:     'TRN_NUMBER',
    COL_SYS_ID:     'TRN_SYS_ID',
    COL_CREATED_ON: 'TRN_CREATED_ON',
    COL_UPDATED_ON: 'TRN_UPDATED_ON',
    COL_CREATED_BY: 'TRN_CREATED_BY',
    COL_UPDATED_BY: 'TRN_UPDATED_BY',

    // Session keys used by NumberPreserver
    SESSION_ACTIVE:  'tracenow_import_active',
    SESSION_NUMBER:  'tracenow_source_number',
    SESSION_SYS_ID:  'tracenow_source_sys_id',

    type: 'TRACENowConfig'
};
